using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // Breaking change 1: EF Core 9 renamed the default discriminator
            // JSON property from "Discriminator" to "$type". Existing documents
            // and direct SQL queries (c.Discriminator) depend on the old name.
            b.HasDiscriminator<string>("Discriminator")
             .HasValue<Product>("Product");

            // Breaking change 2: EF Core 9 changed the synthesized id format
            // from "Product|{key}" to just "{key}". Preserve the old format so
            // existing documents remain readable.
            b.Property<string>("__id")
             .ToJsonProperty("id")
             .HasValueGenerator<LegacyCosmosIdGenerator>();
        });

        // Breaking change 4: HasIndex was silently ignored by the Cosmos
        // provider in EF Core 8. In EF Core 9 it throws — removed.
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = "";
}

